import{_ as t,o as a,c as n,ad as o}from"./chunks/framework.DdcUsuRQ.js";const p=JSON.parse('{"title":"Lightness range","description":"The OKLCH L-channel envelope the engine clamps each role into. Two numbers in 0..1.","frontmatter":{"title":"Lightness range","description":"The OKLCH L-channel envelope the engine clamps each role into. Two numbers in 0..1.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/lightness-range"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/lightness-range"}],["meta",{"property":"og:title","content":"Lightness range: iridis"}],["meta",{"property":"og:description","content":"The OKLCH L-channel envelope the engine clamps each role into. Two numbers in 0..1."}],["meta",{"name":"twitter:title","content":"Lightness range: iridis"}],["meta",{"name":"twitter:description","content":"The OKLCH L-channel envelope the engine clamps each role into. Two numbers in 0..1."}],["meta",{"name":"description","content":"The OKLCH L-channel envelope the engine clamps each role into. Two numbers in 0..1."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Lightness range\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/lightness-range\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/lightness-range.md","filePath":"reference/role-schema/lightness-range.md","lastUpdated":1779033869000}'),i={name:"reference/role-schema/lightness-range.md"};function r(s,e,h,l,c,d){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="lightness-range" tabindex="-1">Lightness range <a class="header-anchor" href="#lightness-range" aria-label="Permalink to &quot;Lightness range&quot;">​</a></h1><p>The <code>[min, max]</code> envelope on the OKLCH <strong>L</strong> channel that the engine clamps the resolved role into. If the seed colour the user supplies falls outside the envelope, <code>clamp:oklch</code> nudges it back in along constant chroma and hue.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Range</th></tr></thead><tbody><tr><td><code>lightnessRange[0]</code></td><td><code>number</code></td><td><code>[0, 1]</code>, lower bound</td></tr><tr><td><code>lightnessRange[1]</code></td><td><code>number</code></td><td><code>[0, 1]</code>, upper bound, <code>&gt;= [0]</code></td></tr></tbody></table><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>clamp:oklch</code> runs after <code>intake:*</code> and before <code>resolve:roles</code>. For each role:</p><ol><li>Look up the seed → OKLCH coordinates.</li><li>If <code>L &lt; lightnessRange[0]</code>, push to <code>lightnessRange[0]</code>.</li><li>If <code>L &gt; lightnessRange[1]</code>, pull to <code>lightnessRange[1]</code>.</li><li>Hue and chroma are untouched in this step.</li></ol><p>The clamp is one-axis. <code>chromaRange</code> and (optionally) <code>hueOffset</code> clamp the other axes.</p><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Lightness envelopes encode role <em>function</em>, not aesthetic preference.</p><ul><li>A <code>text</code> role declares a high L range (e.g. <code>[0.85, 0.96]</code> dark framing, <code>[0.10, 0.22]</code> light framing) because text MUST be readable against the surrounding surface, and readability is a luminance contrast property.</li><li>A <code>surface</code> role declares a low L range in dark framing and a high L range in light framing; the framing flip <em>is</em> the lightness flip.</li><li>A <code>muted</code> text role declares a slightly compressed L range so it reads as quieter than primary text without disappearing.</li></ul><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Author the dark- and light-framing variants as two separate schemas. The user&#39;s framing selection in <code>runtime.framing</code> picks which one feeds the engine; the same role with the same <code>name</code> can occupy <code>[0.85, 0.96]</code> in dark and <code>[0.10, 0.22]</code> in light.</li><li>Keep the range <strong>narrow</strong> for surface and text roles (≤ 0.15 width) so the resolved colour stays inside the role&#39;s perceptual zone regardless of seed.</li><li>Keep the range <strong>wider</strong> for accent roles (≥ 0.20 width) so the seed colour has room to express its identity.</li><li>The range is in <strong>perceptual</strong> lightness, not RGB lightness. 0.5 in OKLCH is the same perceived brightness as 0.5 grey, unlike HSV V or HSL L.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./chroma-range">Chroma range</a>: the orthogonal envelope on the C channel.</li><li><a href="./../oklch">OKLCH reference</a>: full conversion math + range semantics.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>',15)])])}const m=t(i,[["render",r]]);export{p as __pageData,m as default};
